import React, { useState, useEffect, useCallback } from 'react';
import { GoogleMap, Marker, InfoWindow, useJsApiLoader } from '@react-google-maps/api';

const mapContainerStyle = {
  width: '100%',
  height: '500px',
  borderRadius: '12px'
};

const defaultCenter = {
  lat: 16.047079, // Da Nang, Vietnam
  lng: 108.206230
};

// Map options to remove default UI clutter if desired
const options = {
  disableDefaultUI: false,
  zoomControl: true,
};

const StormShieldMap = ({ shelters = [], reports = [], alerts = [] }) => {
  const { isLoaded, loadError } = useJsApiLoader({
    googleMapsApiKey: process.env.REACT_APP_GOOGLE_MAPS_API_KEY,
    libraries: ['places'] // adding places in case future search is needed
  });

  const [center, setCenter] = useState(defaultCenter);
  const [selectedElement, setSelectedElement] = useState(null);
  const [myLocation, setMyLocation] = useState(null);

  useEffect(() => {
    // Attempt to get the user's current location via HTML5 Geolocation API
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const loc = {
            lat: position.coords.latitude,
            lng: position.coords.longitude
          };
          setMyLocation(loc);
          setCenter(loc); // center the map to user location when granted
        },
        (error) => {
          console.warn("Geolocation permission denied or failed. Fallback to default.");
        }
      );
    }
  }, []);

  const onMarkerClick = useCallback((element, type) => {
    setSelectedElement({ ...element, elementType: type });
  }, []);

  if (loadError) return <div>Error loading maps. Check your API key.</div>;
  if (!isLoaded) return <div>Loading interactive map...</div>;

  return (
    <div style={{ position: 'relative', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)', borderRadius: '12px' }}>
      <GoogleMap
        mapContainerStyle={mapContainerStyle}
        zoom={13}
        center={center}
        options={options}
      >
        {/* Current User Location */}
        {myLocation && (
          <Marker 
            position={myLocation}
            icon={{
              path: window.google.maps.SymbolPath.CIRCLE,
              scale: 8,
              fillColor: '#2563EB',
              fillOpacity: 1,
              strokeWeight: 2,
              strokeColor: '#FFFFFF' // Blue dot with white border for current location
            }}
            onClick={() => setSelectedElement({ 
              id: 'me', 
              elementType: 'USER', 
              lat: myLocation.lat, 
              lng: myLocation.lng,
              title: "You are here" 
            })}
          />
        )}

        {/* Shelters */}
        {shelters.map(s => (
          <Marker 
            key={`shelter-${s.id}`} 
            position={{ lat: s.latitude, lng: s.longitude }} 
            icon="http://maps.google.com/mapfiles/ms/icons/green-dot.png"
            onClick={() => onMarkerClick(s, 'SHELTER')}
          />
        ))}

        {/* Approved Hazard Reports */}
        {reports.map(r => (
          <Marker 
            key={`report-${r.id}`} 
            position={{ lat: r.latitude, lng: r.longitude }} 
            icon="http://maps.google.com/mapfiles/ms/icons/red-dot.png"
            onClick={() => onMarkerClick(r, 'REPORT')}
          />
        ))}

        {/* Info Window rendering logic */}
        {selectedElement && (
          <InfoWindow
            position={{ lat: selectedElement.lat || selectedElement.latitude, lng: selectedElement.lng || selectedElement.longitude }}
            onCloseClick={() => setSelectedElement(null)}
          >
            <div>
              {selectedElement.elementType === 'USER' && (
                <strong>{selectedElement.title}</strong>
              )}

              {selectedElement.elementType === 'SHELTER' && (
                <div>
                  <strong>{selectedElement.name}</strong><br/>
                  Address: {selectedElement.address}<br/>
                  Status: {selectedElement.status}<br/>
                  Capacity: {selectedElement.currentOccupancy}/{selectedElement.capacity}
                </div>
              )}

              {selectedElement.elementType === 'REPORT' && (
                <div>
                  <strong>HAZARD: {selectedElement.reportType}</strong><br/>
                  Danger level: {selectedElement.dangerLevel}<br/>
                  Details: {selectedElement.description}
                </div>
              )}
            </div>
          </InfoWindow>
        )}
      </GoogleMap>
    </div>
  );
};

export default StormShieldMap;
